         }
     } catch(e: any) { setError(e.message); if(e.message.includes('Key')) setShowKeyModal(true); }
     setIsLoading(false);
  };

  // --- Render ---
  const modes = [
    { k: 'default', l: 'Default 5X', d: '6 assets: All styles + Video.' },
    { k: 'strict', l: 'Strict Only', d: '2 Flat Lays, 2 Mockups.' },
