                            className={`px-3 py-1 text-xs rounded-full border ${editorState.generationMode===m.k?'bg-blue-600 border-blue-600 text-white':'border-gray-700 text-gray-400 hover:border-blue-500'} transition-all`}
                            title={m.d}
                         >{m.l}</button>
                     ))}
                 </div>
             </div>

             {/* Steps */}
             <div className="space-y-6">
                 <div className={`pl-4 border-l-2 ${editorState.currentStep==='upload'?'border-blue-500':'border-gray-700'}`}>
