                           className={`relative group bg-gray-800 rounded-lg overflow-hidden border transition-all cursor-pointer ${editorState.selectedFlatLays.find(x=>x.id===asset.id)?'border-blue-500 ring-2 ring-blue-500/20':'border-gray-700 hover:border-gray-500'} ${getAssets().length===1?'max-h-full max-w-2xl aspect-auto': 'aspect-square'}`}
                      >
