                          {asset.label && <div className="absolute bottom-0 inset-x-0 bg-black/70 text-white text-[10px] py-1 text-center font-mono uppercase tracking-widest backdrop-blur-sm">{asset.label}</div>}
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                              <button onClick={(e)=>{e.stopPropagation(); setPreviewAsset(asset)}} className="bg-white/10 hover:bg-white/20 p-2 rounded-full backdrop-blur text-white text-lg">🔍</button>
                          </div>
                      </div>
                  ))}
              </div>}
          </div>
      </div>
    </div>
